    const Group *find_group(std::uint32_t group_hash) noexcept
    {
        // Binary search (groups sorted by key at gen time).
        std::size_t lo = 0, hi = kGroupCount;
        while (lo < hi) {
            const std::size_t mid = (lo + hi) >> 1;
            const std::uint32_t k = kGroups[mid].key;
            if (k == group_hash) return &kGroups[mid];
            if (k < group_hash) lo = mid + 1; else hi = mid;
        }
        return nullptr;
    }

    const Group *find_group_by_name(const char *string_key) noexcept
    {
        if (!string_key || !*string_key) return nullptr;
        for (std::size_t i = 0; i < kGroupCount; ++i) {
            const auto *n = kGroups[i].string_key;
            if (!n) continue;
            // Manual strcmp to avoid pulling <cstring>.
            const char *a = n;
            const char *b = string_key;
            while (*a && *a == *b) { ++a; ++b; }
            if (*a == 0 && *b == 0) return &kGroups[i];
        }
        return nullptr;
    }

    std::uint32_t resolve_bgra(std::uint32_t group_hash, std::uint8_t shade_index) noexcept
    {
        const Group *g = find_group(group_hash);
        if (!g) return 0;
        if (shade_index >= g->shade_count) return 0;
        return g->shades[shade_index].bgra;
    }
